using System.ComponentModel; using System.Diagnostics; using System.IO; using System.Text.Json; using System.Windows; using System.Windows.Input;
namespace YNXDeveloper;
public partial class MainWindow : Window {
  Process? server; readonly string statePath=Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),"YNXDeveloper","window.json");
  public MainWindow(){ InitializeComponent(); Loaded+=Start; Closing+=Stop; CommandBindings.Add(new(ApplicationCommands.New,(_,_)=>Click("#create-project"))); CommandBindings.Add(new(ApplicationCommands.Open,(_,_)=>Click("#import-project"))); CommandBindings.Add(new(ApplicationCommands.Save,(_,_)=>Save(null!,null!))); InputBindings.Add(new KeyBinding(ApplicationCommands.Save,new KeyGesture(Key.S,ModifierKeys.Control|ModifierKeys.Shift)){CommandParameter="export"}); RestoreWindow(); }
  async void Start(object sender,RoutedEventArgs e){ var resources=Path.Combine(AppContext.BaseDirectory,"Resources"); server=Process.Start(new ProcessStartInfo("node",$"\"{Path.Combine(resources,"server.mjs")}\""){UseShellExecute=false,CreateNoWindow=true,Environment={ ["PORT"]="4177" }}); await Browser.EnsureCoreWebView2Async(); Browser.CoreWebView2.Settings.AreDevToolsEnabled=true; Browser.Source=new Uri("http://127.0.0.1:4177"); }
  async void Click(string selector){ if(Browser.CoreWebView2!=null) await Browser.ExecuteScriptAsync($"document.querySelector('{selector}')?.click()"); }
  void NewProject(object s,RoutedEventArgs e)=>Click("#create-project"); void OpenProject(object s,RoutedEventArgs e)=>Click("#import-project"); void ExportProject(object s,RoutedEventArgs e)=>Click("#export-project"); void Save(object s,RoutedEventArgs e)=>Browser.CoreWebView2?.ExecuteScriptAsync("document.querySelector('#editor')?.dispatchEvent(new Event('input',{bubbles:true}))"); void Reload(object s,RoutedEventArgs e)=>Browser.Reload(); void Exit(object s,RoutedEventArgs e)=>Close();
  void CheckUpdates(object s,RoutedEventArgs e)=>MessageBox.Show("This unsigned Testnet Preview never downloads or installs updates automatically. A production updater must verify an owner-signed manifest and package.","Signed update boundary",MessageBoxButton.OK,MessageBoxImage.Information);
  void About(object s,RoutedEventArgs e)=>MessageBox.Show("Unsigned Windows Testnet Preview source. Not production signed, installed, or released.","YNX Developer",MessageBoxButton.OK,MessageBoxImage.Information);
  void RestoreWindow(){ try{var v=JsonSerializer.Deserialize<WindowStateRecord>(File.ReadAllText(statePath)); if(v!=null){Left=v.Left;Top=v.Top;Width=Math.Max(960,v.Width);Height=Math.Max(640,v.Height);}}catch{} }
  void Stop(object? sender,CancelEventArgs e){ Directory.CreateDirectory(Path.GetDirectoryName(statePath)!); File.WriteAllText(statePath,JsonSerializer.Serialize(new WindowStateRecord(Left,Top,Width,Height))); try{if(server is {HasExited:false})server.Kill(true);}catch{} }
  record WindowStateRecord(double Left,double Top,double Width,double Height);
}
